use std::io::{self, Read};
use std::str::FromStr;
use std::fmt::Debug;
use std::vec::IntoIter;
use std::cmp::{max, min};

struct InputReader {
    tokens: IntoIter<String>
}

impl InputReader {
    fn new() -> InputReader {
        let mut input = String::new();
        io::stdin().read_to_string(&mut input).unwrap();
        let tokens: Vec<String> = input.split_whitespace().map(|a| a.to_string()).collect();
        InputReader {
            tokens: tokens.into_iter()
        }
    }

    fn next(&mut self) -> String {
        self.tokens.next().unwrap()
    }

    fn next_val<V: FromStr + Debug>(&mut self) -> V {
        self.next().parse::<V>().ok().unwrap()
    }

    fn next_val_array<V: FromStr + Debug>(&mut self, n: usize) -> Vec<V> {
        let mut vec = Vec::with_capacity(n);
        for _ in 0..n {
            vec.push(self.next_val::<V>());
        }
        vec
    }
}


fn main() {
    let mut reader = InputReader::new();
    let n: i64 = reader.next_val();
    let mut answer = (0i64, 0i64);
    let mut diff = i64::max_value();
    for a in 1..(n+1) {
        if n % a == 0 {
            let b = n / a;
            if b >= a && b - a < diff {
                diff = b - a;
                answer = (a, b);
            }
        }
    }
    println!("{} {}", answer.0, answer.1);
}
